import{_ as e,o,c,e as d}from"./app-58c21a21.js";const n={},i=d('<h3 id="nginx是啥" tabindex="-1"><a class="header-anchor" href="#nginx是啥" aria-hidden="true">#</a> Nginx是啥</h3><p><code>nginx</code>是一个高性能的开源<code>Web</code>服务器和反向代理服务器。它常用于前端开发中作为静态资源服务器，用来处理静态文件的访问。使用<code>nginx</code>可以有效地提供静态资源的访问速度，并且具有灵活的配置选项，使其成为前端开发中的重要工具。</p><p>总结：牛皮！</p><h3 id="部署" tabindex="-1"><a class="header-anchor" href="#部署" aria-hidden="true">#</a> 部署</h3><p><code>nginx</code>提供一个容器，可以运行当前已打包的文件</p><ol><li>下载<code>nginx</code>，稳定版、</li><li>在当前<code>nginx</code>目录下，打开终端，输入<code>.\\nginx.exe</code>，回车运行<code>nginx</code>。看到没有报错，光标在闪烁就证明运行成功。</li><li><code>conf</code>文件夹的<code>nginx.conf</code>文件里，<code>http</code>中配置<code>server</code>对象的<code>listen</code>，<code>server_name</code>，<code>location</code>属性。其中<code>root</code>路径为项目运行<code>pnpm run build</code>后打包好的dist文件路径。</li></ol><p>若为<code>https</code>，在<code>https server</code>对象里额外再配置<code>ssl</code>，需要在申请域名时查看证书，再填写对应属性的值。</p><p>最后在浏览器输入<code>server_name</code>属性的值（自己定义的域名或者IP）: <code>listen</code>属性的值（端口号）即可进入项目</p><h3 id="没想到吧" tabindex="-1"><a class="header-anchor" href="#没想到吧" aria-hidden="true">#</a> 没想到吧</h3><p>没了</p>',10),a=[i];function r(t,s){return o(),c("div",null,a)}const l=e(n,[["render",r],["__file","qianduanzaixueNg.html.vue"]]);export{l as default};
